redeem.post("/", zValidator("json", RedeemInputSchema), async (c) => {
  const user2 = c.get("user");
  if (!user2)
    return c.json({ success: false, message: "Unauthorized" }, 401);
  const { rewardId, whatsappNumber } = c.req.valid("json");
  try {
    const result = await db2.transaction(async (tx) => {
      const [item] = await tx.select().from(rewards).where(eq(rewards.id, rewardId)).limit(1);
      if (!item) {
        throw new Error("Reward Item not found");
      }
      const [userRecord] = await tx.select().from(users).where(eq(users.id, user2.id)).limit(1);
      const currentBalance = userRecord?.pointsBalance || 0;
      if (currentBalance < item.requiredPoints) {
        throw new Error("Poin tidak mencukupi");
      }
      await tx.update(users).set({ pointsBalance: sql`${users.pointsBalance} - ${item.requiredPoints}` }).where(eq(users.id, user2.id));
      await tx.insert(pointsLedger).values({
        userId: user2.id,
        amount: -item.requiredPoints,
        source: "redeem",
        description: `Penukaran untuk ${item.title}`,
        createdAt: new Date
      });
      const [request] = await tx.insert(redeemRequests).values({
        nasabahId: user2.id,
        rewardId,
        status: "pending",
        adminNotes: whatsappNumber ? `WA: ${whatsappNumber}` : undefined,
        metadata: { itemName: item.title, price: item.requiredPoints }
      }).returning({ id: redeemRequests.id });
      if (!request)
        throw new Error("Failed to create redeem request");
      return request;
    });
    return c.json({
      success: true,
      message: "Permintaan penukaran berhasil dibuat. Mohon tunggu konfirmasi admin.",
      data: {
        requestId: result.id,
        status: "pending"
      }
    }, 201);
  } catch (error48) {
    console.error("Redeem Logic Error:", error48);
    const isClientError = error48.message === "Poin tidak mencukupi" || error48.message === "Reward Item not found";
    return c.json({ success: false, message: error48.message || "Internal Server Error" }, isClientError ? 400 : 500);
  }
});
var CancelInputSchema = exports_external.object({
  reason: exports_external.string().optional()
});
redeem.post("/:id/cancel", zValidator("json", CancelInputSchema), async (c) => {
  const user2 = c.get("user");
  if (!user2)
    return c.json({ success: false, message: "Unauthorized" }, 401);
  const requestId = c.req.param("id");
  const { reason } = c.req.valid("json");
  try {
    return await db2.transaction(async (tx) => {
      const [request] = await tx.select({
        id: redeemRequests.id,
        status: redeemRequests.status,
        nasabahId: redeemRequests.nasabahId,
        rewardId: redeemRequests.rewardId,
        metadata: redeemRequests.metadata,
        requiredPoints: rewards.requiredPoints
      }).from(redeemRequests).leftJoin(rewards, eq(redeemRequests.rewardId, rewards.id)).where(eq(redeemRequests.id, requestId)).limit(1);
      if (!request) {
        return c.json({ success: false, message: "Request not found (404)" }, 404);
      }
      if (request.nasabahId !== user2.id) {
        return c.json({ success: false, message: "Unauthorized" }, 403);
      }
      const CANCELLABLE_STATES = ["pending"];
      if (!request.status || !CANCELLABLE_STATES.includes(request.status)) {
        return c.json({
          success: false,
          message: `Pesanan dengan status "${request.status}" tidak dapat dibatalkan.`
        }, 400);
      }
      const pointCost = request.metadata?.price || request.requiredPoints || 0;
      await tx.update(users).set({ pointsBalance: sql`${users.pointsBalance} + ${pointCost}` }).where(eq(users.id, user2.id));
      await tx.insert(pointsLedger).values({
        userId: user2.id,
        amount: pointCost,
        source: "refund",
        description: `Refund: Pembatalan User (${reason || "User cancelled request"})`,
        createdAt: new Date
      });
      await tx.update(redeemRequests).set({
        status: "cancelled",
        updatedAt: new Date,
        metadata: { ...request.metadata, cancelledBy: "user", cancelledAt: new Date().toISOString() }
      }).where(eq(redeemRequests.id, requestId));
      return c.json({
        success: true,
        message: "Pembatalan berhasil. Poin telah dikembalikan ke saldo Anda."
      });
    });
  } catch (error48) {
    console.error("Cancel Error:", error48);
    return c.json({ success: false, message: "Gagal membatalkan pesanan" }, 500);
  }
});
