// src/routes/polis.ts
init_src2();
init_drizzle_orm();
var polisRoute = new Hono2;
var InputPolisSchema = exports_external.object({
  polisNumber: exports_external.string().min(3),
  nasabahId: exports_external.string().uuid(),
  agentId: exports_external.string().uuid(),
  premiumAmount: exports_external.number().int().positive()
});
polisRoute.post("/", rbacMiddleware("polis"), zValidator("json", InputPolisSchema), async (c) => {
  const { polisNumber, nasabahId, agentId, premiumAmount } = c.req.valid("json");
  const adminUser = c.get("user");
  try {
    const result = await db2.transaction(async (tx) => {
      const [nasabah] = await tx.select().from(users).where(eq(users.id, nasabahId)).limit(1);
      if (!nasabah)
        throw new Error("Nasabah ID not found");
      const [agent] = await tx.select().from(users).where(eq(users.id, agentId)).limit(1);
      if (!agent)
        throw new Error("Agent ID not found");
      const [existing] = await tx.select().from(polisData).where(eq(polisData.polisNumber, polisNumber)).limit(1);
      if (existing)
        throw new Error("Nomor Polis sudah terdaftar");
      const [newPolis] = await tx.insert(polisData).values({
        polisNumber,
        nasabahId,
        agentId,
        premiumAmount,
        inputBy: adminUser.id
      }).returning();
      const pointsToAward = Math.floor(premiumAmount / 1000);
      if (pointsToAward > 0) {
        await PointsService.addPoints(nasabahId, pointsToAward, "purchase", `Point reward dari Polis #${polisNumber}`, tx);
      }
      return newPolis;
    });
    return c.json({ success: true, data: result }, 201);
  } catch (error48) {
    console.error("Input Polis Error:", error48);
    const isClientError = error48.message === "Nasabah ID not found" || error48.message === "Agent ID not found" || error48.message === "Nomor Polis sudah terdaftar";
    return c.json({ success: false, message: error48.message || "Internal Server Error" }, isClientError ? 400 : 500);
  }
});
