monitoringRoute.post("/watchdog", async (c) => {
  const authHeader = c.req.header("Authorization");
  if (authHeader !== `Bearer ${CRON_SECRET}`) {
    return c.json({ success: false, message: "Unauthorized Cron" }, 401);
  }
  try {
    const fiveMinutesAgo = new Date(Date.now() - 5 * 60 * 1000);
    const staleInteractions = await db2.select().from(waInteractions).where(and(lt(waInteractions.clickedAt, fiveMinutesAgo), eq(waInteractions.isAdminNotified, false))).limit(50);
    if (staleInteractions.length === 0) {
      return c.json({ success: true, message: "No stale interactions found" });
    }
    console.log(`\uD83D\uDC36 Watchdog found ${staleInteractions.length} stale interactions.`);
    const idsToUpdate = staleInteractions.map((i) => i.id);
    for (const item of staleInteractions) {
      await db2.update(waInteractions).set({ isAdminNotified: true }).where(eq(waInteractions.id, item.id));
    }
    return c.json({
      success: true,
      message: `Processed ${staleInteractions.length} stale interactions`,
      ids: idsToUpdate
    });
  } catch (error48) {
    console.error("Watchdog Error:", error48);
    return c.json({ success: false, message: "Internal Server Error" }, 500);
  }
});
